function isSupportedLocale(locale, object) {
  if (!locale) {
    return null;
  }
  locale = locale.toLowerCase().replace(/_/g, "-");
  if (object[locale]) {
    return locale;
  }
  const language = locale.substring(0, 2);
  if (object[language]) {
    return language;
  }
  return null;
}

function findSupportedKey(requestedLocale, object, objectType) {
  const requestedSupported = isSupportedLocale(requestedLocale, object);
  if (requestedSupported) {
    return requestedSupported;
  }
  if (requestedLocale) {
    const keyList = JSON.stringify(Object.keys(object));
    consoleError(`The requested locale "${requestedLocale}" does not contain a supported ${objectType}. We are defaulting to "en". The supported values are ${keyList}.`);
  }
  return "en";
}

async function loadLocale(requestedLocale) {
  try {
    const localeKey = findSupportedKey(requestedLocale, locales, "locale");
    const localeModule = await locales[localeKey]();
    if (localeModule) {
      return localeModule.default;
    }
    consoleError(`The locale data for "${localeKey}" did not load. The application will default to "en".`);
  } catch (error) {
    consoleError(`An error occurred loading the locale data for "${requestedLocale}". The application will default to "en".`, error);
  }
  return enLocaleData;
}

async function loadLanguagePack(providedLanguagePack) {
  if (providedLanguagePack) {
    return fillWithEnglish(providedLanguagePack);
  }
  return enLanguagePack;
}

function fillWithEnglish(languagePack) {
  return {
    ...enLanguagePack,
    ...languagePack
  };
}

function handleBTag(chunks) {
  return React.createElement("b", null, chunks);
}

function handleBRTag() {
  return React.createElement("br", null);
}

function addHTMLSupport(values) {
  values.b = handleBTag;
  values.br = handleBRTag;
  return values;
}

async function loadDayjsLocale(locale) {
  if (!dayjs.Ls[locale]) {
    const previousLocale = dayjs.locale();
    const localePack = await loadLocale(locale);
    dayjs.locale(localePack);
    dayjs.locale(previousLocale);
    const isLoaded = Boolean(dayjs.Ls[locale]);
    if (!isLoaded && locale.length === 2) {
      throw Error("Locale is not recognized.");
    } else if (!isLoaded) {
      return loadDayjsLocale(locale.substring(0, 2));
    }
  }
  return locale;
}

function createEnglishFormat(key) {
  return new IntlMessageFormat(enLanguagePack[key], "en-US");
}

function setIntl(serviceManager, locale, messages) {
  serviceManager.intl = createIntl({
    locale: locale,
    messages: messages
  });
  serviceManager.store.dispatch(actions.setAppStateValue("languagePack", messages));
  serviceManager.store.dispatch(actions.setAppStateValue("locale", locale));
}

function createChatInstance({serviceManager: serviceManager, callRender: callRender}) {
  let wasRendered = false;
  function getMainWindow() {
    return {
      addClassName: name => serviceManager.mainWindow?.addClassName(name),
      removeClassName: name => serviceManager.mainWindow?.removeClassName(name)
    };
  }
  function getMessageInput() {
    return {
      getHTMLElement: () => serviceManager.mainWindow?.getMessageInput()?.getHTMLElement(),
      setValue: value => serviceManager.mainWindow?.getMessageInput()?.setValue(value),
      setEnableEnterKey: value => serviceManager.mainWindow?.getMessageInput()?.setEnableEnterKey(value),
      addChangeListener: listener => serviceManager.mainWindow?.getMessageInput()?.addChangeListener(listener),
      removeChangeListener: listener => serviceManager.mainWindow?.getMessageInput()?.removeChangeListener(listener)
    };
  }
  function getHomeScreenInput() {
    return {
      getHTMLElement: () => serviceManager.mainWindow?.getHomeScreenInput()?.getHTMLElement(),
      setValue: value => serviceManager.mainWindow?.getHomeScreenInput()?.setValue(value),
      setEnableEnterKey: value => serviceManager.mainWindow?.getHomeScreenInput()?.setEnableEnterKey(value),
      addChangeListener: listener => serviceManager.mainWindow?.getHomeScreenInput()?.addChangeListener(listener),
      removeChangeListener: listener => serviceManager.mainWindow?.getHomeScreenInput()?.removeChangeListener(listener)
    };
  }
  let instance = {
    render: () => {
      if (wasRendered) {
        consoleError("The render function has already been called!");
        return Promise.resolve(instance);
      }
      wasRendered = true;
      return callRender();
    },
    on: handlers => {
      serviceManager.eventBus.on(handlers);
      return instance;
    },
    off: handlers => {
      serviceManager.eventBus.off(handlers);
      return instance;
    },
    once: handlers => {
      serviceManager.eventBus.once(handlers);
      return instance;
    },
    updateLanguagePack: newPack => {
      debugLog("Called instance.updateLanguagePack", newPack);
      return serviceManager.actions.updateLanguagePack(newPack);
    },
    updateLocale: newLocale => {
      debugLog("Called instance.updateLocale", newLocale);
      const localePromise = loadLocale(newLocale);
      const languagePackPromise = loadLanguagePack(serviceManager.store.getState().languagePack);
      return Promise.all([ localePromise, languagePackPromise ]).then(([localePack, languagePack]) => {
        dayjs.locale(localePack);
        setIntl(serviceManager, localePack.name, languagePack);
        serviceManager.messageService.pendingLocale = true;
        serviceManager.messageService.localeIsExplicit = true;
      });
    },
    updateCSSVariables: (variables, whiteLabelVariables) => {
      debugLog("Called instance.updateCSSVariables", variables);
      return serviceManager.actions.updateCSSVariables(variables, whiteLabelVariables);
    },
    send: async (message, options) => {
      debugLog("Called instance.send", message, options);
      if (selectInputState(serviceManager.store.getState()).isReadonly) {
        throw new Error("You are unable to send messages in read only mode.");
      }
      return serviceManager.actions.send(message, MessageSendSource.INSTANCE_SEND, options);
    },
    doAutoScroll: (options = {}) => {
      debugLog("Called instance.doAutoScroll", options);
      serviceManager.mainWindow?.doAutoScroll?.(options);
    },
    destroy: () => {
      debugLog("Called instance.destroy");
      serviceManager.store.dispatch(actions.setAppStateValue("isDestroyed", true));
      serviceManager.container?.remove();
      instance = undefined;
    },
    updateInputFieldVisibility: isVisible => {
      debugLog("Called instance.updateInputFieldVisibility", isVisible);
      serviceManager.store.dispatch(actions.updateInputState({
        fieldVisible: isVisible
      }, false));
    },
    updateInputIsDisabled: isDisabled => {
      debugLog("Called instance.updateInputIsDisabled", isDisabled);
      serviceManager.store.dispatch(actions.updateInputState({
        isReadonly: isDisabled
      }, false));
    },
    updateBotUnreadIndicatorVisibility: isVisible => {
      debugLog("Called instance.updateBotUnreadIndicatorVisibility", isVisible);
      serviceManager.store.dispatch(actions.setLauncherProperty("showUnreadIndicator", isVisible));
    },
    changeView: async newView => {
      debugLog("Called instance.changeView", newView);
      let issueWithNewView = false;
      if (!wasRendered) {
        consoleError(`You tried to call "changeView" without ever having called the "render" method. There is no view to change!`);
        issueWithNewView = true;
      }
      const viewTypeValues = Object.values(ViewType);
      if (typeof newView === "string") {
        if (!viewTypeValues.includes(newView)) {
          consoleError(`You tried to change the view but the view you specified is not a valid view name. Please use` + ` the valid view names; ${viewTypeValues.join(", ")}.`);
          issueWithNewView = true;
        }
      } else if (typeof newView === "object") {
        Object.keys(newView).forEach(key => {
          if (!viewTypeValues.includes(key)) {
            consoleError(`You tried to change the state of multiple views by providing an object, however you included the key` + ` "${key}" within the object which is not a valid view name. Please use the valid view names; ` + `${viewTypeValues.join(", ")}.`);
            issueWithNewView = true;
          }
        });
      } else {
        consoleError("You tried to change the view but the view you provided was not a string or an object. You can either change" + ' to one of the supported views by providing a string, ex. "launcher" or "mainWindow". Or you can' + ' change the state of multiple views by providing an object, ex. { "launcher": true, "mainWindow": false,' + " }. Please use one of these supported options.");
        issueWithNewView = true;
      }
      if (!issueWithNewView) {
        await serviceManager.actions.changeView(newView, {
          viewChangeReason: ViewChangeReason.CALLED_CHANGE_VIEW
        });
      }
    },
    notifications: {
      addNotification: notification => {
        debugLog("Called instance.addNotification", notification);
        serviceManager.actions.addNotification(notification);
      },
      removeNotifications: groupID => {
        debugLog("Called instance.removeNotifications", groupID);
        serviceManager.actions.removeNotification(groupID);
      },
      removeAllNotifications: () => {
        debugLog("Called instance.removeAllNotifications");
        serviceManager.actions.removeAllNotifications();
      }
    },
    updateMainHeaderTitle: title => {
      debugLog("Called instance.updateMainHeaderTitle", title);
      if (!title) {
        title = null;
      }
      serviceManager.actions.updateMainHeaderTitle(title);
    },
    updateHomeScreenConfig: homeScreenConfig => {
      debugLog("Called instance.updateHomeScreenConfig", homeScreenConfig);
      const homeScreenConfigClone = cloneDeep(homeScreenConfig);
      const isAIThemeEnabled = serviceManager.store.getState().theme.theme === ThemeType.CARBON_AI;
      if (isAIThemeEnabled) {
        if (homeScreenConfig?.background) {
          consoleWarn("The home screen background can not be changed when the AI theme is enabled.");
          delete homeScreenConfigClone.background;
        }
      }
      serviceManager.actions.updateHomeScreenConfig(withoutEmptyStarters(homeScreenConfigClone));
    },
    getState: () => serviceManager.actions.getPublicWebChatState(),
    writeableElements: createWriteableElementsProxy(serviceManager),
    scrollToMessage: (messageID, animate) => {
      debugLog("Called instance.scrollToMessage", messageID, animate);
      serviceManager.mainWindow?.doScrollToMessage(messageID, animate);
    },
    updateLauncherConfig: config => serviceManager.actions.updateLauncherConfig(config),
    customPanels: serviceManager.customPanelManager,
    updateCustomMenuOptions: options => {
      debugLog("Called instance.updateCustomMenuOptions", options);
      serviceManager.store.dispatch(actions.setAppStateValue("customMenuOptions", options));
    },
    restartConversation: async () => {
      debugLog("Called instance.restartConversation");
      consoleWarn("instance.restartConversation is deprecated. Use instance.messaging.restartConversation instead.");
      return instance.messaging.restartConversation();
    },
    updateIsLoadingCounter(direction) {
      debugLog("Called instance.updateIsLoadingCounter", direction);
      const {store: store} = serviceManager;
      if (direction === "increase") {
        store.dispatch(actions.addIsLoadingCounter(1));
      } else if (direction === "decrease") {
        if (store.getState().botMessageState.isLoadingCounter <= 0) {
          consoleError("You cannot decrease the loading counter when it is already <= 0");
          return;
        }
        store.dispatch(actions.addIsLoadingCounter(-1));
      } else {
        consoleError(`[updateIsLoadingCounter] Invalid direction: ${direction}. Valid values are "increase" and "decrease".`);
      }
    },
    updateIsChatLoadingCounter(direction) {
      debugLog("Called instance.updateIsChatLoadingCounter", direction);
      const {store: store} = serviceManager;
      if (direction === "increase") {
        store.dispatch(actions.addIsHydratingCounter(1));
      } else if (direction === "decrease") {
        if (store.getState().botMessageState.isHydratingCounter <= 0) {
          consoleError("You cannot decrease the hydrating counter when it is already <= 0");
          return;
        }
        store.dispatch(actions.addIsHydratingCounter(-1));
      } else {
        consoleError(`[updateIsChatLoadingCounter] Invalid direction: ${direction}. Valid values are "increase" and "decrease".`);
      }
    },
    updateHeaderConfig: config => {
      const configCopy = cloneDeep(config);
      serviceManager.store.dispatch(actions.updateChatHeaderConfig(configCopy));
    },
    updateMainHeaderAvatar: config => {
      serviceManager.store.dispatch(actions.updateMainHeaderAvatar(config));
    },
    updateBotName: name => serviceManager.actions.updateBotName(name),
    updateBotAvatarURL: url => serviceManager.actions.updateBotAvatarURL(url),
    elements: {
      getMainWindow: getMainWindow,
      getMessageInput: getMessageInput,
      getHomeScreenInput: getHomeScreenInput
    },
    messaging: {
      addMessage: (message, options = {}) => {
        debugLog("Called instance.messaging.addMessage", message, options);
        serviceManager.messageService.messageLoadingManager.end();
        return serviceManager.actions.receive(message, options?.isLatestWelcomeNode ?? false, null, {
          disableFadeAnimation: options?.disableFadeAnimation
        });
      },
      addMessageChunk: async (chunk, options = {}) => {
        debugLog("Called instance.messaging.addMessageChunk", chunk, options);
        serviceManager.messageService.messageLoadingManager.end();
        try {
          await serviceManager.actions.receiveChunk(chunk, null, options);
        } catch (error) {
          consoleError("Error in addMessageChunk", error);
          throw error;
        }
      },
      removeMessages: async messageIDs => {
        debugLog("Called instance.messaging.removeMessages", messageIDs);
        return serviceManager.actions.removeMessages(messageIDs);
      },
      clearConversation: () => {
        debugLog("Called instance.messaging.clearConversation");
        return serviceManager.actions.restartConversation({
          skipHydration: true,
          endHumanAgentConversation: false,
          fireEvents: false
        });
      },
      insertHistory: messages => {
        debugLog("Called instance.messaging.insertHistory", messages);
        return serviceManager.actions.insertHistory(messages);
      },
      restartConversation: async () => {
        debugLog("Called instance.messaging.restartConversation");
        return serviceManager.actions.restartConversation();
      }
    },
    requestFocus: () => {
      debugLog("Called instance.requestFocus");
      serviceManager.appWindow?.requestFocus();
    },
    serviceDesk: {
      endConversation: () => {
        debugLog("Called instance.serviceDesk.endConversation");
        return serviceManager.actions.agentEndConversation(false);
      },
      updateIsSuspended: async isSuspended => {
        debugLog("Called instance.serviceDesk.updateIsSuspended", isSuspended);
        return serviceManager.actions.agentUpdateIsSuspended(isSuspended);
      }
    }
  };
  if (serviceManager.store.getState().config.public.exposeServiceManagerForTesting) {
    const {instance: _, ...serviceManagerForTesting} = serviceManager;
    instance.serviceManager = serviceManagerForTesting;
  }
  if (serviceManager.store.getState().config.public.debug) {
    consoleDebug("[ChatInstanceImpl] Created chat instance", instance);
  }
  return instance;
}

function createWriteableElementsProxy(serviceManager) {
  const elementSet = new Set;
  const handler = {
    get(target, element) {
      if (!elementSet.has(element)) {
        elementSet.add(element);
      }
      return target[element];
    }
  };
  return new Proxy(serviceManager.writeableElements, handler);
}

function inputItemToLocalItem(message, originalUserText, id = uuid(UUIDType.LOCAL_MESSAGE)) {
  const localMessage = {
    item: {
      response_type: MessageResponseTypes.TEXT,
      ...message.input
    },
    ui_state: {
      id: id,
      originalUserText: originalUserText,
      needsAnnouncement: false
    },
    fullMessageID: message.id
  };
  return localMessage;
}

function asArray(value) {
  return Array.isArray(value) ? value : [ value ];
}

async function asyncForEach(array, callbackFunction) {
  for (let index = 0; index < array.length; index++) {
    const value = array[index];
    await callbackFunction(value, index, array);
  }
}

function findLast(array, predicate, startAt) {
  const lastIndex = findLastIndex(array, predicate);
  return lastIndex === -1 ? undefined : array[lastIndex];
}

function findLastIndex(array, predicate, startAt) {
  if (array) {
    const startingIndex = array.length - 1;
    for (let index = startingIndex; index >= 0; index--) {
      const value = array[index];
      if (predicate(value, index, array)) {
        return index;
      }
    }
  }
  return -1;
}

function findLastWithMap(keys, map, predicate) {
  for (let index = keys.length - 1; index >= 0; index--) {
    const key = keys[index];
    const value = map[key];
    if (predicate(value, index, keys)) {
      return value;
    }
  }
  return undefined;
}

function arrayLastValue(array) {
  return array && array.length ? array[array.length - 1] : null;
}

const THREAD_ID_MAIN = "main";

function isResponse(message) {
  return message && message.output !== undefined;
}

function isDateResponseType(localMessage) {
  return localMessage?.item.response_type === MessageResponseTypes.DATE;
}

function addDefaultsToMessage(fullMessage) {
  if (!fullMessage.id) {
    fullMessage.id = uuid(UUIDType.MESSAGE);
  }
  if (!fullMessage.thread_id) {
    fullMessage.thread_id = THREAD_ID_MAIN;
  }
  if (!fullMessage.history) {
    fullMessage.history = {};
  }
  if (!fullMessage.ui_state_internal) {
    fullMessage.ui_state_internal = {};
  }
  if (!fullMessage.history.timestamp) {
    fullMessage.history.timestamp = Date.now();
  }
  if (fullMessage.ui_state_internal.from_history === undefined) {
    fullMessage.ui_state_internal.from_history = false;
  }
  return fullMessage;
}

function isRequest(message) {
  return message?.input !== undefined;
}

function hasLiveHumanAgentMessage(message) {
  return isResponse(message) && Boolean(message.output.generic?.find(item => item?.agent_message_type)) || isRequest(message) && Boolean(message.input.agent_message_type);
}

function isEventRequest(message) {
  return message?.input?.message_type === MessageInputType.EVENT;
}

function isTextItem(item) {
  return item && item.response_type === "text" && item.text !== undefined;
}

function isTyping(message) {
  return message.response_type === MessageResponseTypes.PAUSE && message.typing == true;
}

function isPause(message) {
  return message.response_type === MessageResponseTypes.PAUSE;
}

function isOptionItem(item) {
  return item?.response_type === MessageResponseTypes.OPTION && item.options !== undefined;
}

function createMessageRequestForChoice(choice, relatedResponseID) {
  const messageRequest = {
    id: uuid(UUIDType.MESSAGE),
    thread_id: THREAD_ID_MAIN,
    ...cloneDeep(choice.value)
  };
  messageRequest.history = {
    label: choice.label,
    related_message_id: relatedResponseID
  };
  return messageRequest;
}

function createMessageRequestForButtonItemOption(buttonItem, relatedResponseID) {
  const messageRequest = {
    id: uuid(UUIDType.MESSAGE),
    thread_id: THREAD_ID_MAIN,
    input: null
  };
  if (buttonItem.value?.input?.text) {
    messageRequest.input = cloneDeep(buttonItem.value.input);
  } else {
    messageRequest.input = {
      text: buttonItem.label
    };
  }
  messageRequest.history = {
    related_message_id: relatedResponseID
  };
  return messageRequest;
}

function createWelcomeRequest() {
  return addDefaultsToMessage({
    id: uuid(UUIDType.MESSAGE),
    input: {
      text: ""
    },
    history: {
      silent: true,
      is_welcome_request: true
    },
    thread_id: THREAD_ID_MAIN
  });
}

function createMessageRequestForText(text) {
  return addDefaultsToMessage({
    input: {
      text: text,
      message_type: MessageInputType.TEXT
    }
  });
}

function createMessageRequestForFileUpload(upload) {
  return addDefaultsToMessage({
    id: upload.id,
    input: {
      text: upload.file.name,
      message_type: InternalMessageRequestType.FILE,
      agent_message_type: HumanAgentMessageType.FROM_USER
    },
    history: {
      file_upload_status: FileStatusValue.UPLOADING
    }
  });
}

function createMessageRequestForDate(inputString, userString, relatedResponseID) {
  const messageRequest = createMessageRequestForText(inputString);
  messageRequest.history = {
    label: userString,
    related_message_id: relatedResponseID
  };
  return messageRequest;
}

function createMessageResponseForText(text, threadID = THREAD_ID_MAIN, responseType = MessageResponseTypes.TEXT, context) {
  const textItem = {
    response_type: responseType,
    text: text
  };
  const messageResponse = {
    id: uuid(UUIDType.MESSAGE),
    thread_id: threadID,
    output: {
      generic: [ textItem ]
    }
  };
  return messageResponse;
}

function createMessageResponseForItem(item, context) {
  const messageResponse = {
    output: {
      generic: [ item ]
    }
  };
  return addDefaultsToMessage(messageResponse);
}

function isConnectToHumanAgent(response) {
  return response?.response_type === MessageResponseTypes.CONNECT_TO_HUMAN_AGENT;
}

function isCardResponseType(response) {
  return response?.response_type === MessageResponseTypes.CARD;
}

function isCarouselResponseType(response) {
  return response?.response_type === MessageResponseTypes.CAROUSEL;
}

function isButtonResponseType(response) {
  return response?.response_type === MessageResponseTypes.BUTTON;
}

function isShowPanelButtonType(response) {
  return isButtonResponseType(response) && response.button_type === ButtonItemType.SHOW_PANEL;
}

function isResponseWithNestedItems(item) {
  if (isButtonResponseType(item)) {
    return hasBodyOrFooter(item.panel);
  }
  if (isCardResponseType(item)) {
    return hasBodyOrFooter(item);
  }
  if (isCarouselResponseType(item)) {
    return item.items !== undefined;
  }
  return isGridResponseType(item);
}

function hasBodyOrFooter(item) {
  return item?.body !== undefined || item?.footer !== undefined;
}

function renderAsUserDefinedMessage(messageItem) {
  const responseType = messageItem.response_type;
  switch (responseType) {
   case MessageResponseTypes.TEXT:
   case MessageResponseTypes.IMAGE:
   case MessageResponseTypes.OPTION:
   case MessageResponseTypes.CONNECT_TO_HUMAN_AGENT:
   case MessageResponseTypes.IFRAME:
   case MessageResponseTypes.VIDEO:
   case MessageResponseTypes.AUDIO:
   case MessageResponseTypes.DATE:
   case MessageResponseTypes.CONVERSATIONAL_SEARCH:
   case MessageResponseTypes.TABLE:
   case MessageResponseTypes.INLINE_ERROR:
   case MessageResponseTypes.CARD:
   case MessageResponseTypes.CAROUSEL:
   case MessageResponseTypes.BUTTON:
   case MessageResponseTypes.GRID:
    return false;

   default:
    return true;
  }
}

function hasServiceDesk(config) {
  return Boolean(config.public.serviceDeskFactory);
}

function isItemSupportedInResponseBody(item) {
  switch (item.response_type) {
   case MessageResponseTypes.IMAGE:
   case MessageResponseTypes.IFRAME:
   case MessageResponseTypes.VIDEO:
   case MessageResponseTypes.AUDIO:
   case MessageResponseTypes.TEXT:
   case MessageResponseTypes.USER_DEFINED:
   case MessageResponseTypes.CARD:
   case MessageResponseTypes.GRID:
    return true;

   default:
    return false;
  }
}

function isSingleItemCarousel(messageItem) {
  return isCarouselResponseType(messageItem) && messageItem.items.length === 1;
}

function isFullWidthUserDefined(messageItem) {
  return isUserDefinedItem(messageItem) && messageItem.full_width;
}

function isUserDefinedItem(item) {
  return item?.response_type === MessageResponseTypes.USER_DEFINED;
}

function isGridResponseType(item) {
  return item?.response_type === MessageResponseTypes.GRID;
}

function getOptionType(preference, totalOptions) {
  let type = "button";
  if (preference && preference === "button") {
    type = "button";
  } else if (preference && preference === "dropdown") {
    type = "dropdown";
  } else if (totalOptions > 4) {
    type = "dropdown";
  }
  return type;
}

function isStreamPartialItem(chunk) {
  return Boolean(chunk.partial_item);
}

function isStreamCompleteItem(chunk) {
  return Boolean(chunk.complete_item);
}

function isStreamFinalResponse(chunk) {
  return Boolean(chunk.final_response);
}

function streamItemID(messageID, item) {
  const itemID = item?.streaming_metadata?.id;
  if (!itemID) {
    return null;
  }
  return `${messageID}-${itemID}`;
}

function getMediaDimensions(item) {
  return item.dimensions;
}

function getLastBotResponseWithContext(state) {
  const messageIDs = state.botMessageState.messageIDs || [];
  return findLastWithMap(messageIDs, state.allMessagesByID, message => isResponse(message) && !hasLiveHumanAgentMessage(message) && Boolean(message.context));
}

function outputItemToLocalItem(messageItem, fullMessage, isLatestWelcomeNode = false, disableFadeAnimation = false) {
  const id = streamItemID(fullMessage.id, messageItem) || uuid(UUIDType.LOCAL_MESSAGE);
  const localMessage = {
    ui_state: {
      id: id,
      needsAnnouncement: !fullMessage.ui_state_internal?.from_history,
      disableFadeAnimation: disableFadeAnimation
    },
    item: messageItem,
    fullMessageID: fullMessage.id
  };
  if (isLatestWelcomeNode) {
    localMessage.ui_state.isWelcomeResponse = true;
  }
  return localMessage;
}

function createLocalMessageForInlineError(text) {
  const messageItem = {
    response_type: MessageResponseTypes.INLINE_ERROR,
    text: text
  };
  return createLocalMessageForItem(messageItem);
}

function createLocalMessageForItem(messageItem) {
  const originalMessage = createMessageResponseForItem(messageItem);
  const localMessage = outputItemToLocalItem(messageItem, originalMessage);
  return {
    originalMessage: originalMessage,
    localMessage: localMessage
  };
}

function createLocalMessageItemsForNestedMessageItems(localMessageItem, originalMessage, fromHistory, nestedLocalMessageItems, allowFooter) {
  const {item: item} = localMessageItem;
  if (isGridResponseType(item)) {
    localMessageItem.ui_state.gridLocalMessageItemIDs = item.rows.map(row => row.cells.map(cell => {
      const cellLocalMessageItemIDs = [];
      createLocalMessageItemsForNestedType("items", localMessageItem, cell.items, cellLocalMessageItemIDs, originalMessage, fromHistory, nestedLocalMessageItems, nestedMessageItem => isSupportedMessageItemInBody(localMessageItem.item, nestedMessageItem), false);
      return cellLocalMessageItemIDs;
    }));
  } else if (isCarouselResponseType(item)) {
    localMessageItem.ui_state.itemsLocalMessageItemIDs = [];
    createLocalMessageItemsForNestedType("items", localMessageItem, item.items, localMessageItem.ui_state.itemsLocalMessageItemIDs, originalMessage, fromHistory, nestedLocalMessageItems, nestedMessageItem => isSupportedMessageItemInBody(item, nestedMessageItem), allowFooter);
  } else {
    const bodyItems = item.body || item.panel?.body;
    if (bodyItems) {
      localMessageItem.ui_state.bodyLocalMessageItemIDs = [];
      createLocalMessageItemsForNestedType("body", localMessageItem, bodyItems, localMessageItem.ui_state.bodyLocalMessageItemIDs, originalMessage, fromHistory, nestedLocalMessageItems, nestedMessageItem => isSupportedMessageItemInBody(item, nestedMessageItem), !isShowPanelButtonType(item));
    }
    if (!allowFooter) {
      return;
    }
    const footerItems = item.footer || item.panel?.footer;
    if (footerItems) {
      localMessageItem.ui_state.footerLocalMessageItemIDs = [];
      createLocalMessageItemsForNestedType("footer", localMessageItem, footerItems, localMessageItem.ui_state.footerLocalMessageItemIDs, originalMessage, fromHistory, nestedLocalMessageItems, nestedMessageItem => isSupportedMessageItemInFooter(item, nestedMessageItem), !isShowPanelButtonType(item));
    }
  }
}

function createLocalMessageItemsForNestedType(type, localMessageItem, items, nestedMessageItemIDs, originalMessage, fromHistory, nestedLocalMessageItems, isSupported, allowFooter) {
  items.forEach(nestedMessageItem => {
    if (isSupported(nestedMessageItem)) {
      const nestedLocalMessageItem = outputItemToLocalItem(nestedMessageItem, originalMessage, false, true);
      nestedMessageItemIDs.push(nestedLocalMessageItem.ui_state.id);
      nestedLocalMessageItems.push(nestedLocalMessageItem);
      if (isResponseWithNestedItems(nestedLocalMessageItem.item)) {
        createLocalMessageItemsForNestedMessageItems(nestedLocalMessageItem, originalMessage, fromHistory, nestedLocalMessageItems, allowFooter);
      }
    } else {
      consoleError(`The "${localMessageItem.item.response_type}" response type does not support "${nestedMessageItem.response_type}" in "${type}" array.`);
    }
  });
}

function isSupportedMessageItemInBody(rootMessageItem, nestedMessageItem) {
  switch (rootMessageItem.response_type) {
   case MessageResponseTypes.CARD:
    return !isCardResponseType(nestedMessageItem) && isItemSupportedInResponseBody(nestedMessageItem);

   case MessageResponseTypes.CAROUSEL:
    return isCardResponseType(nestedMessageItem);

   case MessageResponseTypes.BUTTON:
    return rootMessageItem.button_type === ButtonItemType.SHOW_PANEL && isItemSupportedInResponseBody(nestedMessageItem);

   case MessageResponseTypes.GRID:
    return !isCardResponseType(nestedMessageItem) && isItemSupportedInResponseBody(nestedMessageItem);

   default:
    return false;
  }
}

function isSupportedMessageItemInFooter(rootMessageItem, nestedMessageItem) {
  if (isButtonResponseType(nestedMessageItem)) {
    if (isShowPanelButtonType(rootMessageItem)) {
      return !isShowPanelButtonType(nestedMessageItem);
    }
    return true;
  }
  return false;
}

